// MonthDataService reads static month JSON (Refs: R1,R5,R9,G1,G16)
import { logger } from '../../logging/logger'; // G16 structured logging

export interface DaySummary {
  date: string;
  postsCount: number;
  sentiments: { positive: number; neutral: number; negative: number };
  summary: string;
  hasDetail: boolean;
  generatedAt: string;
}

export interface MonthDataServiceOptions {
  dataRoot?: string;
  fetchFn?: typeof fetch;
}

function trimTrailingSlash(url: string): string {
  return url.endsWith('/') ? url.slice(0, -1) : url;
}

function resolveDataRoot(options?: MonthDataServiceOptions): string {
  // G1: Configurable data root via env or runtime global
  const explicit = options?.dataRoot;
  const envUrl = typeof process !== 'undefined' ? process.env?.STATIC_DATA_URL : undefined;
  const globalUrl = typeof globalThis !== 'undefined' ? (globalThis as any).__STATIC_DATA_URL__ : undefined;
  const candidate = explicit || envUrl || globalUrl || '/data';
  return trimTrailingSlash(candidate);
}

export class MonthDataService {
  private readonly fetchFn: typeof fetch;
  private readonly dataRoot: string;
  private readonly cache = new Map<string, DaySummary[]>();

  constructor(options?: MonthDataServiceOptions) {
    this.fetchFn = options?.fetchFn ?? fetch;
    this.dataRoot = resolveDataRoot(options);
  }

  async getMonth(year: number, month: number, options?: { forceRefresh?: boolean }): Promise<DaySummary[]> {
    const monthStr = `${year}-${String(month).padStart(2, '0')}`;
    const cacheKey = monthStr;

    if (!options?.forceRefresh && this.cache.has(cacheKey)) {
      return this.cache.get(cacheKey)!; // R9: simple client cache to avoid duplicate requests
    }

    const url = `${this.dataRoot}/month/${monthStr}.json`; // R1 static path
    const fetchFn = this.fetchFn; // Preserve native fetch realm binding to avoid "Illegal invocation" in browser
    const resp = await fetchFn(url);

    if (!resp.ok) {
      logger.error('Month data request failed', { status: resp.status, statusText: resp.statusText }); // G16
      throw new Error(`Month data request failed (${resp.status} ${resp.statusText})`);
    }

    const payload = (await resp.json()) as { days: Array<{ date: string; counts: any; postsCount: number; summary?: string; hasDetail?: boolean; generatedAt?: string }> };
    const mapped: DaySummary[] = (payload?.days || []).map((d) => ({
      date: d.date,
      postsCount: d.postsCount,
      sentiments: d.counts ?? { positive: 0, neutral: 0, negative: 0 },
      summary: d.summary ?? '',
      hasDetail: d.hasDetail ?? true,
      generatedAt: d.generatedAt ?? ''
    }));
    this.cache.set(cacheKey, mapped);
    return mapped;
  }
}
