// DaySummaryService retrieves day detail from static JSON (Refs: R1.1, R1.2, R5.1, G1, G16)
import { logger } from '../../logging/logger'; // G16 structured logging

export interface DaySummary {
  date: string;
  summary: string;
  sentiments: { positive: number; neutral: number; negative: number };
  topics: string[];
  source: 'static';
  fallbackMessage?: string;
}

export interface DaySummaryServiceOptions {
  dataRoot?: string;
  fetchFn?: typeof fetch;
}

function trimTrailingSlash(url: string): string {
  return url.endsWith('/') ? url.slice(0, -1) : url;
}

function resolveDataRoot(options?: DaySummaryServiceOptions): string {
  // G1: Configurable data root via env or runtime global
  const explicit = options?.dataRoot;
  const envUrl = typeof process !== 'undefined' ? process.env?.STATIC_DATA_URL : undefined;
  const globalUrl = typeof globalThis !== 'undefined' ? (globalThis as any).__STATIC_DATA_URL__ : undefined;
  const candidate = explicit || envUrl || globalUrl || '/data';
  return trimTrailingSlash(candidate);
}

export class DaySummaryService {
  private readonly fetchFn: typeof fetch;
  private readonly dataRoot: string;
  private readonly cache = new Map<string, DaySummary>();

  constructor(options?: DaySummaryServiceOptions) {
    this.fetchFn = options?.fetchFn ?? fetch;
    this.dataRoot = resolveDataRoot(options);
  }

  async getSummary(date: string, options?: { forceRefresh?: boolean }): Promise<DaySummary> {
    if (!options?.forceRefresh && this.cache.has(date)) {
      return this.cache.get(date)!; // R3: reuse cached detail for repeat hovers/clicks
    }

    const year = date.slice(0, 4);
    const month = date.slice(5, 7);
    const url = `${this.dataRoot}/days/${year}/${month}/${date}.json`; // R1.1 static path
    const fetchFn = this.fetchFn; // Preserve native fetch realm binding to avoid "Illegal invocation" in browser
    const resp = await fetchFn(url);

    if (!resp.ok) {
      logger.error('Day summary data request failed', { status: resp.status, statusText: resp.statusText }); // G16
      throw new Error(`Day summary data request failed (${resp.status} ${resp.statusText})`);
    }

    const payload = (await resp.json()) as any;
    const normalizedTopics = Array.isArray(payload.topics)
      ? payload.topics.map((t: any) => (typeof t === 'string' ? t : String(t?.phrase ?? t?.topic ?? ''))).filter(Boolean)
      : [];
    const sentiments = payload.counts ?? payload.sentiments ?? { positive: 0, neutral: 0, negative: 0 };
    const summaryText = payload.summary ?? payload.fallbackMessage ?? 'No summary available';

    const normalized: DaySummary = {
      date: payload.date ?? date,
      summary: summaryText,
      sentiments,
      topics: normalizedTopics,
      source: 'static',
      fallbackMessage: payload.fallbackMessage ?? summaryText,
    };

    this.cache.set(date, normalized);
    return normalized;
  }
}
