// Simplified bootstrap placeholder until Angular CLI tooling installed.
import { AppComponent } from './app/app.component';
import { MonthDataService } from './app/services/month-data.service';
import { DaySummaryService, DaySummary } from './app/services/day-detail.service';
import { CalendarDayCellComponent } from './app/calendar-day-cell/calendar-day-cell.component';
import { sentimentClass, formatTriple } from './app/utils/color-util'; // R2 reuse
import { logger } from './logging/logger'; // G16

// Temporary lightweight bootstrap (Option B esbuild) before full Angular CLI (Refs: N1,N2,R1,R2)
const monthDataService = new MonthDataService(); // R1,R5
const daySummaryService = new DaySummaryService(); // R1.1,R5.1

const popover = ensurePopover();
let activePopoverDate: string | null = null;

function ensurePopover(): HTMLDivElement {
  const existing = document.getElementById('day-popover');
  if (existing) {
    return existing as HTMLDivElement;
  }

  const el = document.createElement('div');
  el.id = 'day-popover';
  el.setAttribute('role', 'dialog'); // R3 accessibility
  el.setAttribute('aria-live', 'polite');
  el.hidden = true;
  document.body.appendChild(el);
  return el;
}

function positionPopover(target: HTMLElement) {
  const rect = target.getBoundingClientRect();
  popover.style.left = `${rect.left + window.scrollX}px`;
  popover.style.top = `${rect.bottom + window.scrollY + 8}px`;
}

function showPopoverContent(target: HTMLElement, content: string) {
  positionPopover(target);
  popover.innerHTML = content;
  popover.hidden = false;
}

function hidePopover() {
  popover.hidden = true;
  popover.innerHTML = '';
  activePopoverDate = null;
}

function showPopoverLoading(target: HTMLElement, date: string) {
  activePopoverDate = date;
  showPopoverContent(target, `<div class="popover-title">${date}</div><div class="popover-loading">Loading day summary...</div>`);
}

function showPopoverError(target: HTMLElement, date: string, errorMessage: string) {
  activePopoverDate = date;
  showPopoverContent(target, `<div class="popover-title">${date}</div><div class="popover-error">Error: ${errorMessage}</div>`);
}

function renderPopoverSummary(target: HTMLElement, summary: DaySummary) {
  activePopoverDate = summary.date;
  const topics = summary.topics.length > 0 ? summary.topics.map((t) => `<li>${t}</li>`).join('') : '';
  const sentiments = summary.sentiments ? `Sentiments: ${formatTriple(summary.sentiments)}` : '';
  const content = summary.topics.length > 0
    ? `<ul class="popover-topics">${topics}</ul>`
    : `<div class="popover-row">${summary.summary || summary.fallbackMessage || 'No summary available'}</div>`;
  showPopoverContent(
    target,
    `<div class="popover-title">${summary.date}</div>${content}${sentiments ? `<div class="popover-row">${sentiments}</div>` : ''}`
  );
}

async function loadMonth() { // R1 fetch month summaries
  const statusEl = document.getElementById('status');
  const grid = document.getElementById('grid');
  if (!statusEl || !grid) return;
  
  // Get current month/year (R10 UTC)
  const url = new URL(window.location.href);
  const yearParam = url.searchParams.get('year');
  const monthParam = url.searchParams.get('month');
  const now = new Date();
  const year = yearParam ? parseInt(yearParam, 10) : now.getUTCFullYear();
  const month = monthParam ? parseInt(monthParam, 10) : (now.getUTCMonth() + 1); // 1-12
  
  try {
    statusEl.textContent = 'Loading month data...';
    // R1,R5: Fetch static month JSON via service (G1-configurable)
    const days = await monthDataService.getMonth(year, month);
    statusEl.textContent = '';
    grid.hidden = false;
    grid.innerHTML = '';

    days.forEach((d: any) => {
      const triple = formatTriple(d.sentiments); // R2
      const cls = sentimentClass(d.sentiments);
      const cell = document.createElement('div');
      cell.className = `day ${cls}`;
      cell.dataset.date = d.date; // R10 UTC date label
      cell.tabIndex = 0;
      cell.setAttribute('role', 'button');
      cell.setAttribute('aria-haspopup', 'dialog');
      cell.setAttribute('aria-label', `Open details for ${d.date}`);
      const topicPreview = document.createElement('div');
      topicPreview.className = 'topic-preview';
      topicPreview.textContent = d.summary ? `Summary: ${d.summary}` : 'Summary: unavailable';

      cell.innerHTML = `<strong>${d.date}</strong><br/>Posts: ${d.postsCount}<br/>${triple}`;
      cell.appendChild(topicPreview);

      const showDetail = async () => {
        // R3: Show popover on hover/click
        showPopoverLoading(cell, d.date);
        try {
          // R1.1: Fetch day summary via API
          const summary = await daySummaryService.getSummary(d.date);
          if (activePopoverDate !== d.date) return; // Ignore stale responses
          renderPopoverSummary(cell, summary);
        } catch (e) {
          logger.error('Failed to load day summary', { error: e instanceof Error ? e.message : String(e), date: d.date });
          showPopoverError(cell, d.date, e instanceof Error ? e.message : 'Unknown error');
        }
      };

      cell.addEventListener('click', showDetail);
      cell.addEventListener('mouseenter', showDetail);
      cell.addEventListener('focus', showDetail);
      cell.addEventListener('mouseleave', () => {
        hidePopover();
      });

      grid.appendChild(cell);
    });
  } catch (e) {
    statusEl.textContent = `Error loading data: ${e instanceof Error ? e.message : 'Unknown error'}`;
    logger.error('Failed to load month data', { error: e instanceof Error ? e.message : String(e) });
  }
}

// Preserve previous export for tests expecting bootstrap symbol.
export function bootstrap() { return new AppComponent(); }

loadMonth();
