// color-util (Task 8) Refs: R2
// Provides sentiment triple formatting and CSS class mapping based on dominant sentiment.

export interface Sentiments { positive: number; neutral: number; negative: number; }
export type Dominant = 'positive' | 'neutral' | 'negative' | 'empty' | 'mixed';

// Format triple positive:neutral:negative (R2)
export function formatTriple(s: Sentiments): string {
  return `${s.positive}:${s.neutral}:${s.negative}`; // R2
}

function dominantSentiment(s: Sentiments): Dominant {
  const { positive, neutral, negative } = s;
  if (positive === 0 && neutral === 0 && negative === 0) return 'empty';
  // Determine strict max
  const entries: Array<[Dominant, number]> = [
    ['positive', positive],
    ['neutral', neutral],
    ['negative', negative],
  ];
  entries.sort((a,b) => b[1] - a[1]);
  const [first, second] = entries;
  if (first[1] === second[1]) return 'mixed';
  return first[0];
}

// Map to CSS class (R2)
export function sentimentClass(s: Sentiments): string {
  const dom = dominantSentiment(s);
  switch(dom) {
    case 'empty': return 'sentiment-empty';
    case 'positive': return 'sentiment-pos';
    case 'neutral': return 'sentiment-neu';
    case 'negative': return 'sentiment-neg';
    case 'mixed':
    default: return 'sentiment-mixed';
  }
}
